namespace BgCommon.Script.Runtime.Configuration;/// <summary>/// 表示脚本的配置信息类，用于定义程序集路径、脚本路径及相关的引用关系./// </summary>[Serializable]public class ScriptConfig{    internal const string ExtensionScript = ".csx";    internal const string ExtensionTemplate = ".tpl";    /// <summary>    /// Initializes a new instance of the <see cref="ScriptConfig"/> class.    /// </summary>    public ScriptConfig()    {        this.Extension = ExtensionScript;    }    /// <summary>    /// Initializes a new instance of the <see cref="ScriptConfig"/> class.    /// </summary>    /// <param name="directory">文件存储路径.</param>    /// <param name="libraryRefDirectory">引用程序集所在路径.</param>    /// <param name="extension">文件扩展名.</param>    /// <param name="name">配置文件名称.</param>    public ScriptConfig(        string directory,        string libraryRefDirectory,        string? extension = null,        string? name = null)    {        // 验证构造函数参数是否为空.        ArgumentNullException.ThrowIfNull(directory, nameof(directory));        ArgumentNullException.ThrowIfNull(libraryRefDirectory, nameof(libraryRefDirectory));        // 为属性赋值，显式使用 this 标识.        this.Name = name ?? Guid.NewGuid().ToString();        this.LibraryRefDirectory = libraryRefDirectory;        this.Directory = directory;        this.Extension = extension ?? ExtensionScript;        this.Usings = new List<string>();        this.References = new List<LibraryRef>();    }    /// <summary>    /// Gets or sets 配置名称.    /// </summary>    public string Name { get; set; } = string.Empty;    /// <summary>    /// Gets or sets 引用程序集所在路径.    /// </summary>    public string LibraryRefDirectory { get; set; } = string.Empty;    /// <summary>    /// Gets or sets 脚本文件扩展名.    /// </summary>    public string Extension { get; set; } = string.Empty;    /// <summary>    /// Gets or sets 脚本文件存储路径.    /// </summary>    public string Directory { get; set; } = string.Empty;    /// <summary>    /// Gets or sets 预定义的命名空间列表.    /// </summary>    public List<string> Usings { get; protected set; } = new List<string>();    /// <summary>    /// Gets or sets 引用的外部程序集列表.    /// </summary>    public List<LibraryRef> References { get; protected set; } = new List<LibraryRef>();    /// <summary>    /// 文件全路径（用于 LoadAsync 加载初始代码）.    /// </summary>    /// <param name="name">文件名.</param>    /// <returns>返回指定文件名的全路径.</returns>    public string GetFilePath(string name)    {        ArgumentNullException.ThrowIfNullOrEmpty(name, nameof(name));        if (string.IsNullOrEmpty(this.Directory))        {            return string.Empty;        }        return Path.Combine(this.Directory, $"{name}{this.Extension}");    }    /// <summary>    /// 添加引用.    /// </summary>    /// <param name="libraryRef">引用库实例.</param>    /// <returns>返回自身.</returns>    public ScriptConfig With(LibraryRef libraryRef)    {        ArgumentNullException.ThrowIfNull(libraryRef, nameof(libraryRef));        if (this.References.Any(r => r.Equals(libraryRef)))        {            LogRun.Warn(LocalizationProviderFactory.GetString("引用库{Library}已存在", libraryRef.ToString()));        }        this.References.Add(libraryRef);        return this;    }    /// <summary>    /// 添加命名空间.    /// </summary>    /// <param name="usings">命名空间.</param>    /// <returns>返回自身.</returns>    public ScriptConfig With(string usings)    {        this.Usings.Add(usings);        return this;    }}